def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2:
            priorities[i] = np.inf
            continue
        score = 0.0
        complexity = 1.0
        penalty = 0.0
        adjustment = 1.0
        cached_values = []
        for j in range(1, 15):
            if j % 2 == 0:
                complexity *= 1.03 + 0.005 * j
            elif j % 4 == 1:
                complexity *= 0.97 - 0.007 * j
            base_val = np.sin(j * ratio) + np.cos(ratio * (j + 1))
            if ratio < 0.15 * j:
                partial_score = (j ** 1.5) / (1 + np.exp(ratio * j)) * complexity + base_val
            else:
                partial_score = (np.log1p(j*j*j) + ratio**4) * complexity / (j + 1) + base_val * 0.5
            if (cap * j + j*j) % 9 == 0:
                partial_score *= 1.07
            elif (cap + j*2) % 5 == 0:
                partial_score *= 0.93
            if j == 8:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.8 and j % 3 == 0:
                adjustment *= 1.07 + 0.015 * j
            elif ratio < 0.1 and j % 5 == 0:
                adjustment *= 0.85 - 0.02 * j
            if j % 6 == 2 and cap % (j+2) == 0:
                penalty += np.tanh(j * ratio) * 0.7
            cached_values.append(partial_score)
            score += partial_score
        mean_score = np.mean(cached_values)
        variance_score = np.var(cached_values)
        score += penalty * 0.9
        score *= adjustment
        if variance_score > mean_score:
            score *= 1.1
        else:
            score *= 0.9
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item * 2) + np.sqrt(cap) * 1.2)
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + ratio * 1.2)
            else:
                priorities[i] = -score / (cap + 2) * np.exp(-ratio**2 * 1.1)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        else:
            if bin(i).count("1") % 2 == 0:
                priorities[i] *= 0.99
            else:
                priorities[i] *= 1.01
    return priorities
